(function(){'use strict';let sidebarOpen=false;let sidebarElement=null;let overlayElement=null;let toggleButton=null;const MOBILE_BREAKPOINT=768;function init(){sidebarElement=document.querySelector('sadec-sidebar');if(!sidebarElement){return;}createOverlay();createToggleButton();addEventListeners();handleResize();}function createOverlay(){overlayElement=document.createElement('div');overlayElement.className='mobile-nav-overlay';overlayElement.style.cssText=` position: fixed;top: 0;left: 0;width: 100vw;height: 100vh;background: rgba(0,0,0,0.5);opacity: 0;visibility: hidden;transition: opacity 0.3s ease,visibility 0.3s ease;z-index: 999;`;document.body.appendChild(overlayElement);}function createToggleButton(){toggleButton=document.querySelector('.nav-toggle,.mobile-menu-toggle,[data-mobile-toggle]');if(!toggleButton){toggleButton=document.createElement('button');toggleButton.className='mobile-menu-toggle';toggleButton.setAttribute('aria-label','Toggle menu');toggleButton.setAttribute('aria-expanded','false');toggleButton.innerHTML=`<span class="material-symbols-outlined">menu</span>`;toggleButton.style.cssText=` display: none;position: fixed;top: 16px;right: 16px;z-index: 1000;background: var(--md-sys-color-surface);border: none;border-radius: 50%;width: 48px;height: 48px;cursor: pointer;box-shadow: 0 2px 8px rgba(0,0,0,0.2);`;document.body.appendChild(toggleButton);}}function addEventListeners(){toggleButton.addEventListener('click',toggleSidebar);overlayElement.addEventListener('click',closeSidebar);window.addEventListener('resize',handleResize);document.addEventListener('keydown',handleKeyDown);addTouchGestures();handleSidebarLinks();}function toggleSidebar(){if(sidebarOpen){closeSidebar();}else{openSidebar();}}function openSidebar(){sidebarOpen=true;sidebarElement.classList.add('mobile-open');overlayElement.style.opacity='1';overlayElement.style.visibility='visible';toggleButton.setAttribute('aria-expanded','true');const icon=toggleButton.querySelector('.material-symbols-outlined');if(icon){icon.textContent='close';}document.body.style.overflow='hidden';trapFocus(sidebarElement);announceToScreenReader('Menu opened');}function closeSidebar(){sidebarOpen=false;sidebarElement.classList.remove('mobile-open');overlayElement.style.opacity='0';overlayElement.style.visibility='hidden';toggleButton.setAttribute('aria-expanded','false');const icon=toggleButton.querySelector('.material-symbols-outlined');if(icon){icon.textContent='menu';}document.body.style.overflow='';releaseFocusTrap();announceToScreenReader('Menu closed');}function handleResize(){const isMobile=window.innerWidth<=MOBILE_BREAKPOINT;const display=isMobile ? 'flex' : 'none';toggleButton.style.display=display;if(!isMobile&&sidebarOpen){closeSidebar();}}function handleKeyDown(event){if(event.key==='Escape'&&sidebarOpen){closeSidebar();toggleButton.focus();}}function addTouchGestures(){let touchStartX=0;let touchEndX=0;document.addEventListener('touchstart',(e)=>{touchStartX=e.changedTouches[0].screenX;},{passive: true});document.addEventListener('touchend',(e)=>{touchEndX=e.changedTouches[0].screenX;handleSwipe(touchStartX,touchEndX);},{passive: true});}function handleSwipe(startX,endX){const diff=endX-startX;const threshold=50;if(diff>threshold&&startX<30&&!sidebarOpen){openSidebar();}if(diff<-threshold&&sidebarOpen){closeSidebar();}}function handleSidebarLinks(){sidebarElement.addEventListener('click',(event)=>{const target=event.target;const navItem=target.closest('.nav-item,a[href]');if(navItem&&!navItem.classList.contains('nav-section-label')){setTimeout(()=>{closeSidebar();},150);}});}let previousActiveElement=null;function trapFocus(element){previousActiveElement=document.activeElement;const focusableElements=element.querySelectorAll('a[href],button,textarea,input,select,[tabindex]:not([tabindex="-1"])');if(focusableElements.length>0){focusableElements[0].focus();}}function releaseFocusTrap(){if(previousActiveElement){previousActiveElement.focus();previousActiveElement=null;}}function announceToScreenReader(message){const announcement=document.createElement('div');announcement.setAttribute('role','status');announcement.setAttribute('aria-live','polite');announcement.style.cssText=` position: absolute;width: 1px;height: 1px;padding: 0;margin:-1px;overflow: hidden;clip: rect(0,0,0,0);white-space: nowrap;border: 0;`;announcement.textContent=message;document.body.appendChild(announcement);setTimeout(()=>{document.body.removeChild(announcement);},1000);}window.MobileNav={init,toggle: toggleSidebar,open: openSidebar,close: closeSidebar,isOpen:()=>sidebarOpen};if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',init);}else{init();}})();(function(){'use strict';function initResponsiveTables(){const tables=document.querySelectorAll('.data-table');tables.forEach((table)=>{const headers=Array.from(table.querySelectorAll('thead th')).map((th)=>th.textContent.trim());table.querySelectorAll('tbody tr').forEach((row)=>{const cells=row.querySelectorAll('td');cells.forEach((cell,index)=>{if(headers[index]&&!cell.hasAttribute('data-label')){cell.setAttribute('data-label',headers[index]);}});});if(window.innerWidth<=768){table.classList.add('mobile-cards');}});}function initResponsiveGrids(){const grids=document.querySelectorAll('.stats-grid,.grid-2,.grid-3,.grid-4');grids.forEach((grid)=>{const updateGrid=()=>{const width=window.innerWidth;if(width<=480){grid.style.gridTemplateColumns='1fr';}else if(width<=768){if(grid.classList.contains('grid-4')||grid.classList.contains('stats-grid')){grid.style.gridTemplateColumns='repeat(2,1fr)';}else{grid.style.gridTemplateColumns='1fr';}}else if(width<=1024){if(grid.classList.contains('grid-4')||grid.classList.contains('stats-grid')){grid.style.gridTemplateColumns='repeat(2,1fr)';}}else{grid.style.gridTemplateColumns='';}};updateGrid();window.addEventListener('resize',updateGrid);});}function initTouchButtons(){const buttons=document.querySelectorAll('.btn,button');buttons.forEach((button)=>{const rect=button.getBoundingClientRect();if(rect.width<44||rect.height<44){button.style.minWidth='44px';button.style.minHeight='44px';}});}function initLazyLoading(){if('IntersectionObserver' in window){const imageObserver=new IntersectionObserver((entries)=>{entries.forEach((entry)=>{if(entry.isIntersecting){const img=entry.target;if(img.dataset.src){img.src=img.dataset.src;img.removeAttribute('data-src');}imageObserver.unobserve(img);}});});document.querySelectorAll('img[data-src]').forEach((img)=>{imageObserver.observe(img);});}}function init(){initResponsiveTables();initResponsiveGrids();initTouchButtons();initLazyLoading();}if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',init);}else{init();}window.ResponsiveUtils={init,initResponsiveTables,initResponsiveGrids,initTouchButtons,initLazyLoading};})();